-- ************************************** ANALYTICS.VW_PROVIDER_PERFORMANCE
CREATE VIEW ANALYTICS.VW_PROVIDER_PERFORMANCE
(
  CREATED_TIMESTAMP,
  CREATED_BY_NAME,
  UPDATED_TIMESTAMP,
  UPDATED_BY_NAME
)
AS
SELECT 
    pr.PROVIDER_KEY,
    pr.PROVIDER_ID,
    pr.PROVIDER_NPI,
    pr.PROVIDER_NAME,
    pr.SPECIALTY,
    pr.SUBSPECIALTY,
    f.FACILITY_KEY,
    f.FACILITY_ID,
    f.FACILITY_NAME,
    COUNT(DISTINCT e.ENCOUNTER_KEY) AS TOTAL_ENCOUNTERS,
    COUNT(DISTINCT CASE WHEN e.READMISSION_FLAG = TRUE THEN e.ENCOUNTER_KEY END) AS READMISSION_COUNT,
    ROUND(COUNT(DISTINCT CASE WHEN e.READMISSION_FLAG = TRUE THEN e.ENCOUNTER_KEY END)::FLOAT / 
          NULLIF(COUNT(DISTINCT e.ENCOUNTER_KEY), 0) * 100, 2) AS READMISSION_RATE,
    ROUND(AVG(e.LENGTH_OF_STAY_DAYS), 2) AS AVG_LENGTH_OF_STAY,
    SUM(e.TOTAL_CHARGES_AMOUNT) AS TOTAL_CHARGES,
    SUM(e.TOTAL_PAYMENTS_AMOUNT) AS TOTAL_PAYMENTS,
    COUNT(DISTINCT fp.PROCEDURE_FACT_KEY) AS TOTAL_PROCEDURES,
    ROUND(AVG(COALESCE(fp.ANESTHESIA_MINUTES, 0)), 2) AS AVG_ANESTHESIA_MINUTES
FROM ANALYTICS.DIM_PROVIDER pr
LEFT JOIN ANALYTICS.DIM_FACILITY f ON 1=1
LEFT JOIN ANALYTICS.FACT_ENCOUNTER e ON pr.PROVIDER_KEY = e.PROVIDER_KEY AND f.FACILITY_KEY = e.FACILITY_KEY
LEFT JOIN ANALYTICS.FACT_PROCEDURE fp ON e.ENCOUNTER_KEY = fp.ENCOUNTER_KEY
WHERE pr.IS_CURRENT = TRUE AND pr.ACTIVE_FLAG = TRUE
GROUP BY 
    pr.PROVIDER_KEY,
    pr.PROVIDER_ID,
    pr.PROVIDER_NPI,
    pr.PROVIDER_NAME,
    pr.SPECIALTY,
    pr.SUBSPECIALTY,
    f.FACILITY_KEY,
    f.FACILITY_ID,
    f.FACILITY_NAME;

